```go
package tmux

// Session defines the contract for a managed terminal multiplexer session.
// The instance layer depends on this interface, not the concrete TmuxSession.
type Session interface {
    // Lifecycle
    Start(workDir string) error
    Restore() error
    Close() error
    DoesSessionExist() bool

    // I/O
    SendKeys(keys string) error
    TapEnter() error
    TapRight() error
    SendPermissionResponse(choice PermissionChoice) error
    CapturePaneContent() (string, error)
    CapturePaneContentWithOptions(start, end string) (string, error)
    HasUpdated() (updated bool, hasPrompt bool)
    HasUpdatedWithContent() (updated bool, hasPrompt bool, content string, captured bool)
    GetPanePID() (int, error)

    // Attach/Detach
    Attach() (chan struct{}, error)
    Detach()
    DetachSafely() error
    SetDetachedSize(width, height int) error

    // Accessors
    GetPTY() *os.File
    GetSanitizedName() string

    // Configuration (builder-style, called before Start)
    SetAgentType(agentType string)
    SetInitialPrompt(prompt string)
    SetTaskEnv(taskNumber, waveNumber, peerCount int)
    SetSessionTitle(title string)
    SetTitleFunc(fn func(workDir string, beforeStart time.Time, title string))
    NewReset(name, program string, skipPermissions bool) Session
}

type PermissionChoice int

const (
    PermissionAllowOnce PermissionChoice = iota
    PermissionAllowAlways
    PermissionReject
)

const (
    ProgramClaude   = "claude"
    ProgramOpenCode = "opencode"
    TmuxPrefix      = "kas_"
)
```

**`session/tmux/adapter.go`** — program-specific behavior:

```go
package tmux

// ProgramAdapter encapsulates program-specific behavior for readiness
// detection, prompt detection, trust-screen handling, and CLI prompt syntax.
type ProgramAdapter interface {
    ReadyString() string
    NeedsTrustTap() bool
    DetectPrompt(plainContent string) bool
    MaxWaitTime() time.Duration
    BuildPromptArg(prompt, workDir string, writeFile func(string) string) string
    SupportsCliPrompt() bool
}

// AdapterFor returns the adapter for the given program string, or nil
// if the program has no special handling.
func AdapterFor(program string) ProgramAdapter { ... }

type claudeAdapter struct{}
type opencodeAdapter struct{}
```

**`session/tmux/monitor.go`** — extracted status monitor:

```go
package tmux

// StatusMonitor tracks pane content changes via hashing with ANSI stripping
// and debounce logic to prevent false Running→Ready transitions.
type StatusMonitor struct { ... }

func NewStatusMonitor() *StatusMonitor { ... }
// RecordContent hashes content (after ANSI strip), returns true if content
// is considered "updated" (changed or still within debounce window).
func (m *StatusMonitor) RecordContent(content string) bool { ... }
// RecordFailure increments the failure counter. Returns true if the failure
// should be logged (first failure, then every 75th).
func (m *StatusMonitor) RecordFailure() bool { ... }
```

